const parkCount = locations.filter(l => l.type === 'park').length;
const roadCount = locations.filter(l => l.type === 'road').length;
const cityCount = [...new Set(locations.map(l => l.city))].length;

console.log(`共收录 ${locations.length} 条数据：`);
